var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이쪽은 모두 처리했습니다.","JPN":"こちらはすべて処理しました。","ENG":"This section is secure.","TWN":"這邊都處理乾淨了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"나도 끝났어, 미나 소대장.","JPN":"私も終わったよ、ミナ小隊長。","ENG":"Same here, Commander.","TWN":"米娜隊長，我也都處理好了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그거 하지 말라니까?","JPN":"だからその呼び方はやめてってば！","ENG":"I told you to cut that out!","TWN":"就叫你不要叫我隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 소대장 자리에 관심 없어! 내 이름을 딴 소대는 더!","JPN":"私は小隊長の席なんか興味ないの！　自分の名前がついた小隊なら尚更！","ENG":"I don't care about being a commander! And even less about having a squad named after me!","TWN":"我才不想當時什麼隊長！用我的名字來命名小隊更是沒興趣！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"농담이야, 농담.","JPN":"冗談よ、冗談。","ENG":"I'm just messing with you.","TWN":"我開玩笑的啦～"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 흥분하는 걸 보니까 은근히 맘에 들었던 거 아냐?","JPN":"でも割とテンション高めだし、何気に気に入ってるんじゃない？","ENG":"But the way you get all worked up tells me you were kind of enjoying it, no?","TWN":"這麼激動幹嘛？難道是因為被我說中了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니야!","JPN":"違うってば！","ENG":"No!","TWN":"我才沒有！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"어? 침식파가 계속 나타나네?","JPN":"あれ？　侵食波がまた出てきた。","ENG":"Huh? The Corruption Rays just keep popping up.","TWN":"喔？侵蝕波還在持續出現欸？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"하나 둘, 마이크 테스트~ 두 번째, 세 번째 침식체 군집이 곧 도착합니다~","JPN":"テステス、マイクテスト～。え～っと、2つ目3つ目の侵食体群がもうすぐ到着しま～す。","ENG":"Mic test, one two… We've got the second and third waves of C.O.s coming soon.","TWN":"1、2、1、2，麥克風測試～第二波、第三波侵蝕體攻勢即將抵達～"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나야, 이거…… 조금 위험한 거 아냐?","JPN":"ミナちゃん、これ……ちょっと危ないんじゃない？","ENG":"Mina… Isn't this getting a bit too dangerous?","TWN":"米娜……好像有點不妙欸？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이렇게 계속 싸우다간 수색하기도 전에 힘이 바닥나겠어.","JPN":"このまま戦い続けたら、捜索する前に体力が尽きちゃうかも。","ENG":"At this rate, we'll run out of steam before we even start searching.","TWN":"再繼續打下去，在找到人之前我們會先累死吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"뭘 망설이나, 숙녀 분들!","JPN":"何をためらうのだ、お嬢ちゃんたちよ！","ENG":"Don't you worry about a thing, ladies!","TWN":"淑女們！有什麼好煩惱的呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L21_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"오랜만에 기름값을 할 때가 왔군.","JPN":"久々に給料分働ける時が来たな。","ENG":"Because Titan's in the house!","TWN":"終於可以賺些油費囉！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"길을 열어 주겠네! 어서 가서 그 소년을 구해 오게나!","JPN":"道を開いてやろう！　早く行ってあの少年を救いたまえ！","ENG":"I'll open up a path for you! Go save that boy!","TWN":"我來開路！你們快去把那個少年救出來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니……. 타이탄이라고 했지?","JPN":"そういえば……タイタンって言ったよね？","ENG":"Hmm… Titan, was it?","TWN":"它是……叫泰坦嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리 회사가 저런 로봇을 어떻게 산 거야?","JPN":"うちの会社があんなロボットをどうやって買ったの？","ENG":"How did our company end up buying a robot like that?","TWN":"我們公司怎麼會買那種機器人？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"명령 불복종으로 퓨처 앳 워 재단이 폐기 처분하려던 걸 부사장님이 헐값에 구매하셨다던대?","JPN":"命令不服従でフューチャーアットウォー財団が\\n廃棄処分しようとしたのを、副社長が安値で購入したって聞いたよ？","ENG":"Apparently the Vice President got a bargain for it because the Future-at-War Foundation wanted to scrap it for insubordination.","TWN":"聽說它原本因為不服從命令，差點遭到天啟兵器財團進行報廢處理，後來被副總用便宜的價格買回來的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"폐기 처분? 아니, 고장이 나면 고쳐 써야지.","JPN":"廃棄処分？　いや、故障したなら直して使うべきじゃない？","ENG":"Scrap it? Couldn't they fix it instead?","TWN":"報廢處理？為什麼？壞掉的話修理就好啦？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"글쎄. 대정화 전쟁 때 한창 만들던 괴상한 병기라 그럴지도.","JPN":"さあね。大浄化戦争時に作られた変わった兵器だからかも。","ENG":"Who knows. Maybe it's one of those weird weapons they made during the Grand Purification War that didn't work right.","TWN":"誰知道？說不定是淨化之戰時大量製造的詭異兵器。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괴상한 병기라니?","JPN":"変わった兵器って？","ENG":"Weird weapons?","TWN":"詭異兵器？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"생각해 봐. 이족보행 로봇 따윌 굳이 만들 필요가 없잖아.","JPN":"ほら、二足歩行ロボットなんかわざわざ作る必要がないでしょ。","ENG":"Think about it. Bipedal robots are completely useless.","TWN":"你想想，哪有必要做什麼雙足步行機器人？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"쓸데없이 피탄 면적만 넓지, 관절이 많아서 신뢰성도 떨어지지, 전투 중에 균형이라도 잃으면 큰일이지.","JPN":"無駄に被弾面積が広いだけだし、関節が多くて信頼性も低いし、戦闘中にバランスでも崩したら大変でしょ？","ENG":"They're more exposed to damage, all those joints mean there's more parts to malfunction, and they tip over during fighting.","TWN":"而且體積那麼大，很容易成為攻擊目標，然後關節那麼多是要幹嘛？萬一在戰鬥中失去平衡不就尷尬了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"초과학 수준의 신소재랑 반중력 모터 같은 정신 나간 오파츠를 때려 박아서 만든 사치품 중의 사치품이랄까.","JPN":"超科学レベルの新素材と反重力モーターみたいな\\nとんでもないオーパーツをぶち込んで作った贅沢品の中の贅沢品とも言えるね。","ENG":"It's nothing but an outlandish luxury packed with crazy sci-fi stuff like anti-gravity motors.","TWN":"完全就只是為了展現技術力而創造的產物，可以說是奢侈品中的奢侈品吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 이 나이에 칭찬을 들으니 쑥쓰럽구만!","JPN":"ガハハ！　この歳で褒められると照れてしまうな！","ENG":"Haha! You're making this old machine blush with such compliments!","TWN":"哈哈！這把年紀還能聽到淑女的讚美，真是害羞呢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"할아버지! 대단해!","JPN":"おじいちゃん！　すごい！","ENG":"Grandpa! That's impressive!","TWN":"爺爺好厲害喔！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……칭찬 아닌데.","JPN":"……褒めてないよ。","ENG":"…That wasn't a compliment.","TWN":"這不是稱讚……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"애초에 신형 전차 같은 건 안 만들고 저런 물건이나 개발했으니까 FAW가…….","JPN":"そもそも新型戦車とかじゃなくて、あんなのばかり開発したからFAWが……","ENG":"Anyway, inventing crazy stuff like that instead of new main battle tanks is probably why FAW-","TWN":"當初就不做新型電車，偏偏要開發這種東西，FAW才……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우효~! 3류 태스크포스 주제에 거대로봇이 있어? 꽤 로망을 아는 회사였잖아?","JPN":"ウヒョー！！　三流タスクフォースカンパニーのくせに\\n巨大ロボットを持ってたの？　意外とロマンがわかる会社じゃない！","ENG":"Daang! You guys got a giant robot? You guys know what you're doing after all!","TWN":"哇喔～！區區的三流特遣勢力公司竟然買得起這麼大的機器人？看來你們公司很前瞻欸？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"졸업하고 나면 이 나이엘님의 3지망 정도로는 고려해 주지.","JPN":"卒業したら、このナイエル様の第3志望くらいには考慮してあげる。","ENG":"Fine, I'll consider your company as one of my backup options when I graduate.","TWN":"等我畢業後就把你們公司列為第三志願吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"돌아가면 너희 사장한테 전해. 영광으로 알라고.","JPN":"帰ったらあんたたちの社長に伝えて。栄光に思いなさいってね。","ENG":"Go tell your boss when this is over. They should consider it an honor.","TWN":"回去告訴你們老闆，這可是他的榮幸！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……아, 그래. 배속 희망 소대는 꼭 펜릴 소대로 하길 바래.","JPN":"……ああ、そう。希望配属先はぜひフェンリル小隊にしてね。","ENG":"…Uh, sure. Make sure you apply to the Fenrir Squad though.","TWN":"……喔～好的好的，那就請務必加入芬里爾小隊囉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알트 소대에 오면 작전 중 오발사고가 날지도 모르니까.","JPN":"アルト小隊に来たら、作戦中に誤射事故が起こるかもしれないから。","ENG":"If you join ALT Squad, we might end up with a fratricide during a mission.","TWN":"來阿爾特小隊的話，我怕會發生擦槍走火的意外。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……잘은 모르겠지만 어쨌든 우리편이라는 거지?","JPN":"……よくわからないけど、とにかく味方ってことだよね？","ENG":"…So I guess that means you're on our side?","TWN":"……雖然聽不太懂，總之你跟我們是同一國的吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그렇다네!","JPN":"ああ、そうだとも！","ENG":"Indeed!","TWN":"沒錯！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"마음 같아서는 나도 수색에 참가하고 싶네만, 이 덩치에 잠입 임무는 어렵겠지.","JPN":"気持ちとしては吾輩も捜索に参加したいが、この体で潜入任務は難しいだろう。","ENG":"I wish I could join you on the search, but my size isn't exactly optimal for infiltration.","TWN":"雖然我也很想一起去找人，但我的體型很難不引人注目。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"대신 자네들이 안전하게 돌아갈 수 있도록 함선을 사수하고 있겠네!","JPN":"代わりに君たちが安全に帰れるように艦船を死守しておこう！","ENG":"Instead, I'll keep the ship secure so you can go back home safely!","TWN":"所以！我決定要誓死守護艦船，等你們安全回來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고마워. 로봇이지만 든든하네.","JPN":"ありがとう。ロボットだけど心強いね。","ENG":"Thank you. You may be just a robot, but that's most reassuring.","TWN":"謝謝你，雖然是機器人，但是很可靠呢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 동료의 믿음이야말로 나의 연료 첨가제라네!","JPN":"ハハ！　同僚の信頼こそが吾輩の燃料添加剤になる！","ENG":"Haha! A colleague's trust is like a fuel additive to me!","TWN":"哈哈！夥伴的信任就是我的燃料添加劑！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……연료 첨가제?","JPN":"……燃料添加剤？","ENG":"…Fuel additive?","TWN":"……燃料添加劑？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우리 장갑차도 잘못 썼다가 엔진 나갔는데. 그거 완전 사기……","JPN":"確かにうちの装甲車に使ってエンジンが壊れたけど、完全に詐欺……","ENG":"We tried using some in our APC but it wrecked the engine. It's just a big scam…","TWN":"我們的裝甲車也因為使用錯誤導致引擎故障，那個根本就……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"안 물어봤어. 알트 소대장님.","JPN":"聞いてないよ。アルト小隊長。","ENG":"No one asked you. ALT Squad Commander.","TWN":"阿爾特小隊長，我沒有問你！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없이 아군 사격이나 계획하지 말고 빨리 움직이기나 해.","JPN":"無駄話はこの辺にして、さっさと動こう。","ENG":"Stop coming up with fratricide schemes and get moving.","TWN":"有時間在那邊質疑自己人，不如趕快出發去找人吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};